'use strict';

function classifySequence(previous, candidate) {
  if (candidate === previous) return { kind: 'duplicate', distance: 0 };
  if (candidate > previous) return { kind: 'forward', distance: candidate - previous };
  return { kind: 'stale', distance: previous - candidate };
}

module.exports = { classifySequence };

