'use strict';

const { classifySequence } = require('./serialOrder');

class Replica {
  constructor() {
    this.current = null;
  }

  accept(frame) {
    if (this.current === null) {
      this.current = { sequence: frame.sequence, value: frame.value };
      return true;
    }
    const order = classifySequence(this.current.sequence, frame.sequence);
    if (order.kind === 'forward' && frame.sequence > this.current.sequence) {
      this.current = { sequence: frame.sequence, value: frame.value };
      return true;
    }
    return false;
  }
}

module.exports = { Replica };

