'use strict';

const test = require('node:test');
const assert = require('node:assert/strict');
const { decodeFrame } = require('../src/frameCodec');
const { Replica } = require('../src/replica');

test('ordinary forward frames advance and duplicates are ignored', () => {
  const replica = new Replica();
  assert.equal(replica.accept({ sequence: 40, value: 'a' }), true);
  assert.equal(replica.accept({ sequence: 41, value: 'b' }), true);
  assert.equal(replica.accept({ sequence: 41, value: 'duplicate' }), false);
  assert.equal(replica.current.value, 'b');
});

test('decoded transport frames enter the ordinary replica flow', () => {
  const payload = Buffer.alloc(4);
  payload.writeUInt16BE(500, 0);
  payload.writeUInt16BE(77, 2);
  const replica = new Replica();
  assert.equal(replica.accept(decodeFrame(payload)), true);
  assert.deepEqual(replica.current, { sequence: 500, value: 77 });
});

test('an older ordinary frame cannot replace current state', () => {
  const replica = new Replica();
  replica.accept({ sequence: 800, value: 'new' });
  assert.equal(replica.accept({ sequence: 799, value: 'late' }), false);
  assert.equal(replica.current.value, 'new');
});
